from agent import *from models.products import *import reXCAT = ['Gutschein', 'Neu', 'Sale', 'Marken']def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('https://www.loesdau.de/'), process_frontpage, dict())def process_frontpage(data, context, session):    strip_namespace(data)    cats1 = data.xpath('//ul[@class="level1"]/li')    for cat1 in cats1:        name1 = cat1.xpath('a/text()').string()        if name1 not in XCAT:            cats2 = cat1.xpath('ul[@class="level2"]/li')            for cat2 in cats2:                name2 = cat2.xpath('a/text()').string()                cats3 = cat2.xpath('ul[@class="level3"]/li/a')                if cats3:                    for cat3 in cats3:                        name3 = cat3.xpath('text()').string()                        url = cat3.xpath('@href').string()                                                print('cat=', name1+'|'+name2+'|'+name3)                        # session.queue(Request(url), process_prodlist, dict(cat=name1+'|'+name2+'|'+name3))                else:                    url = cat2.xpath('a/@href').string()                                        print('cat2=', name1+'|'+name2)                    # session.queue(Request(url), process_prodlist, dict(cat=name1+'|'+name2))def process_subcategory(data, context, session):    strip_namespace(data)    subcats = data.xpath('//div[@class="category"]//h2/a')    if not subcats:        process_prodlist(data, context, session)    for subcat in subcats:        name = subcat.xpath('text()').string()        url = subcat.xpath('@href').string()        session.queue(Request(url), process_subcategory, dict(cat=context['cat']+'|'+name))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[contains(@class, "product  tileproduct")]')    for prod in prods:        name = prod.xpath('.//h2//span[@itemprop="name"]/text()').string()        manufacturer = prod.xpath('.//div[@class="brand"]/meta/@content').string()        url = prod.xpath('.//h2/a[@class="title link"]/@href').string().split('?')[0]        sku = prod.xpath('@data-rel').string()        revs_cnt = prod.xpath('.//div/span[@itemprop="ratingCount"]/text()').string()        if revs_cnt and int(revs_cnt) > 0:            session.queue(Request(url), process_product, dict(context, name=name, manufacturer=manufacturer, url=url, sku=sku))    next_url = data.xpath('//a[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.manufacturer = context.get('manufacturer')    product.url = context['url']    product.category = context['cat']    product.ssid = product.url.split('/')[-1].replace('.html', '')    product.sku = context.get('sku')    if data.xpath('//span/a[contains(., "Alle Bewertungen")]'):        revs_url = "https://www.loesdau.de/bewertungen/" + product.ssid + '.html'        session.queue(Request(revs_url), process_reviews, dict(product=product, revs_url=revs_url))    else:        context['product'] = product        process_reviews(data, context, session)def process_reviews(data, context, session):    strip_namespace(data)    product = context['product']    revs = data.xpath('//div[@itemprop="review"]')    for rev in revs:        review = Review()        review.type = 'user'        review.url = context.get('revs_url') or product.url        date = rev.xpath('.//p[@class="date SMALL"]/text()[contains(., " am ")]').string()        if date:            review.date = date.split('am ')[-1].strip(' -')        author = rev.xpath('.//b[@itemprop="author"]/text()').string()        if author:            review.authors.append(Person(name=author, ssid=author))        is_verified = rev.xpath('.//span[@class="verified-rating"]/text()').string()        if is_verified and is_verified == 'bestätigter Kauf':            review.add_property(type='is_verified_buyer', value=True)        grade_overall = rev.xpath('.//meta[@itemprop="ratingValue"]/@content').string()        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))        excerpt = rev.xpath('.//span[@itemprop="description"]/text()').string(multiple=True)        if excerpt:            excerpt = remove_emoji(excerpt).strip()            if excerpt:                review.properties.append(ReviewProperty(type="excerpt", value=excerpt))                review.ssid = review.digest() if author else review.digest(excerpt)                product.reviews.append(review)    next_url = data.xpath('//li[@class="next"]/a/@href').string()    if next_url:        session.do(Request(next_url, max_age=0), process_reviews, dict(revs_url=next_url, product=product))    elif product.reviews:        session.emit(product)